const contentIdeaId = Number($json.body?.contentIdeaId || $json.contentIdeaId || 0);
const workflowRunId = Number($json.body?.workflowRunId || $json.workflowRunId || 0);
const idempotencyKey = String($json.body?.idempotencyKey || $json.idempotencyKey || '').trim() || null;
const tiktokSoundId = String($json.body?.tiktokSoundId || $json.tiktokSoundId || '').trim() || null;

if (!contentIdeaId || contentIdeaId <= 0) {
  throw new Error('contentIdeaId invalide ou manquant: ' + contentIdeaId);
}
if (!workflowRunId || workflowRunId <= 0) {
  throw new Error('workflowRunId invalide ou manquant: ' + workflowRunId);
}

return [{ json: { idempotencyKey, contentIdeaId, workflowRunId, tiktokSoundId } }];

const data = $json.body;
if (!data || !data.accessToken) throw new Error('accessToken manquant du contexte');
if (!data.title) throw new Error('title manquant du contexte');
if (!data.shotstackUrl) throw new Error('shotstackUrl manquant du contexte');
if (!data.selectedPrivacyLevel) throw new Error('selectedPrivacyLevel manquant du contexte');

return [{ json: { accessToken: data.accessToken, title: String(data.title).trim().slice(0, 150), shotstackUrl: data.shotstackUrl, selectedPrivacyLevel: data.selectedPrivacyLevel, contentIdeaId: $('Validate Input').item.json.contentIdeaId, tiktokSoundId: $('Validate Input').item.json.tiktokSoundId || null } }];

const videoSize = Number($json.headers?.['content-length'] || 0);
if (videoSize <= 0) throw new Error('Video size invalid: ' + videoSize);
if (videoSize > 1073741824) throw new Error('Video exceeds 1GB limit: ' + videoSize); // 1GB limit
return [{ json: { videoSize } }];

const data = $json.body || $json.data;
if ($json.statusCode >= 400) throw new Error('TikTok API error: ' + $json.statusCode + ' ' + JSON.stringify(data));
if (!data.data?.publish_id) throw new Error('No publish_id returned from TikTok');
if (!data.data?.upload_url) throw new Error('No upload_url returned from TikTok');

return [{ json: { publishId: data.data.publish_id, uploadUrl: data.data.upload_url, contentIdeaId: $('Validate Init Context').item.json.contentIdeaId } }];

const baseUrl = String($env.APP_VIDEO_OPS_BACKEND_BASE_URL || '').replace(/\/+$/, '');
const callbackSecret = String($env.APP_VIDEO_OPS_WORKFLOW_CALLBACK_SECRET || '');
const workflowRunId = Number($('Validate Input').item.json.workflowRunId || 0);
let idempotencyKey = '';
try { idempotencyKey = String($('Validate Input').first().json.idempotencyKey || '').trim(); } catch (e) {}
const contentIdeaId = Number($('Extract TikTok Response').item.json.contentIdeaId || 0);
const publishId = $('Extract TikTok Response').item.json.publishId || '';
const uploadUrl = $('Extract TikTok Response').item.json.uploadUrl || '';

if (!baseUrl) throw new Error('APP_VIDEO_OPS_BACKEND_BASE_URL manquante');
if (!callbackSecret) throw new Error('APP_VIDEO_OPS_WORKFLOW_CALLBACK_SECRET manquante');
if (!workflowRunId) throw new Error('workflowRunId manquant');

const body = JSON.stringify({
  status: 'SUCCEEDED',
  message: 'Init publish TikTok termine.',
  responsePayload: JSON.stringify({ contentIdeaId, publishId, uploadUrl })
});

const http = require('http');
const https = require('https');
const { URL } = require('url');
const url = new URL(baseUrl + '/api/video-ops/workflow-runs/' + workflowRunId + '/complete');
const client = url.protocol === 'https:' ? https : http;

const response = await new Promise((resolve, reject) => {
  let attempts = 0;
  const maxAttempts = 3;

  const tryRequest = () => {
    const req = client.request({
      protocol: url.protocol,
      hostname: url.hostname,
      port: url.port || (url.protocol === 'https:' ? 443 : 80),
      path: url.pathname + url.search,
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Content-Length': Buffer.byteLength(body),
        'X-Video-Ops-Callback-Secret': callbackSecret,
        ...(idempotencyKey ? { 'X-Idempotency-Key': idempotencyKey } : {}),
        'X-Request-Timestamp': Date.now().toString()
      }
    }, (res) => {
      let data = '';
      res.on('data', (chunk) => { data += chunk; });
      res.on('end', () => resolve({ statusCode: res.statusCode || 0, body: data }));
    });

    req.on('error', (err) => {
      attempts++;
      if (attempts < maxAttempts) {
        setTimeout(tryRequest, Math.pow(2, attempts) * 1000);
      } else {
        reject(err);
      }
    });

    req.setTimeout(20000, () => {
      req.destroy();
      attempts++;
      if (attempts < maxAttempts) {
        setTimeout(tryRequest, Math.pow(2, attempts) * 1000);
      } else {
        reject(new Error('Callback timeout'));
      }
    });

    req.write(body);
    req.end();
  };

  tryRequest();
});

if (response.statusCode < 200 || response.statusCode >= 300) {
  throw new Error('Callback failed: ' + response.statusCode + ' ' + response.body);
}

return [{ json: { ok: true, contentIdeaId, publishId, uploadUrl, callbackStatusCode: response.statusCode } }];

const baseUrl = String($env.APP_VIDEO_OPS_BACKEND_BASE_URL || '').replace(/\/+$/, '');
const callbackSecret = String($env.APP_VIDEO_OPS_WORKFLOW_CALLBACK_SECRET || '');
const contentIdeaId = Number($('Validate Input').item.json.contentIdeaId || 0);
const workflowRunId = Number($('Validate Input').item.json.workflowRunId || 0);
let idempotencyKey = '';
try { idempotencyKey = String($('Validate Input').first().json.idempotencyKey || '').trim(); } catch (e) {}
const error = $json;

let errorMessage = 'Unknown error';
if (typeof error === 'string') errorMessage = error;
else if (error.message) errorMessage = error.message;
else if (error.error?.message) errorMessage = error.error.message;

if (!baseUrl || !callbackSecret || !workflowRunId) {
  return [{ json: { status: 'FAILED', message: 'Missing config for error callback' } }];
}

const body = JSON.stringify({
  status: 'FAILED',
  message: 'Init publish failed: ' + errorMessage.slice(0, 200),
  responsePayload: JSON.stringify({ contentIdeaId, error: errorMessage.slice(0, 500) })
});

const http = require('http');
const https = require('https');
const { URL } = require('url');
const url = new URL(baseUrl + '/api/video-ops/workflow-runs/' + workflowRunId + '/complete');
const client = url.protocol === 'https:' ? https : http;

const response = await new Promise((resolve, reject) => {
  let attempts = 0;
  const maxAttempts = 2;

  const tryRequest = () => {
    const req = client.request({
      protocol: url.protocol,
      hostname: url.hostname,
      port: url.port || (url.protocol === 'https:' ? 443 : 80),
      path: url.pathname + url.search,
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Content-Length': Buffer.byteLength(body),
        'X-Video-Ops-Callback-Secret': callbackSecret,
        ...(idempotencyKey ? { 'X-Idempotency-Key': idempotencyKey } : {}),
        'X-Request-Timestamp': Date.now().toString()
      }
    }, (res) => {
      let data = '';
      res.on('data', (chunk) => { data += chunk; });
      res.on('end', () => resolve({ statusCode: res.statusCode || 0, body: data }));
    });

    req.on('error', (err) => {
      attempts++;
      if (attempts < maxAttempts) {
        setTimeout(tryRequest, Math.pow(2, attempts) * 1000);
      } else {
        resolve({ statusCode: 0, body: 'Error callback failed: ' + err.message });
      }
    });

    req.setTimeout(15000, () => {
      req.destroy();
      attempts++;
      if (attempts < maxAttempts) {
        setTimeout(tryRequest, Math.pow(2, attempts) * 1000);
      } else {
        resolve({ statusCode: 0, body: 'Error callback timeout' });
      }
    });

    req.write(body);
    req.end();
  };

  tryRequest();
});

return [{ json: { status: 'FAILED', message: 'Error callback sent (best effort)', statusCode: response.statusCode } }];
